const BREVO_KEY = '[REDACTED_BREVO_KEY]';
const CIRCLE_TOKEN = '[REDACTED_CIRCLE_TOKEN]';
const COMMUNITY_ID = 503593;

// 1. R&eacute;cup&eacute;rer tous les membres Circle
let allMembers = [];
let page = 1;
let hasMore = true;
while (hasMore) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://app.circle.so/api/v1/community_members?community_id=' + COMMUNITY_ID + '&per_page=100&page=' + page,
    headers: { 'Authorization': 'Token ' + CIRCLE_TOKEN }
  });
  if (resp.length === 0) {
    hasMore = false;
  } else {
    allMembers = allMembers.concat(resp);
    page++;
  }
  if (page > 20) hasMore = false;
}

// 2. Identifier les inactifs (derniere activite > 14 jours)
const now = new Date();
const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
const inactiveMembers = [];

for (const m of allMembers) {
  const lastSeen = m.last_seen_at || m.updated_at || m.created_at;
  if (lastSeen) {
    const lastDate = new Date(lastSeen);
    if (lastDate < fourteenDaysAgo) {
      inactiveMembers.push({
        name: m.name || '',
        email: m.email || '',
        last_seen: lastSeen,
        days_inactive: Math.floor((now - lastDate) / (24 * 60 * 60 * 1000))
      });
    }
  }
}

if (inactiveMembers.length === 0) {
  return [{ json: { success: true, message: 'Aucun membre inactif > 14j', count: 0 } }];
}

// 3. Taguer les inactifs dans Brevo
const brevoHeaders = { 'api-key': BREVO_KEY, 'Content-Type': 'application/json' };
for (const m of inactiveMembers) {
  if (m.email) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.brevo.com/v3/contacts',
        headers: brevoHeaders,
        body: {
          email: m.email,
          attributes: { STATUT_MEMBRE: 'inactive' },
          updateEnabled: true
        }
      });
    } catch(e) {}
  }
}

// 4. Envoyer alerte a Laurie + Catherine
const today = new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

let tableRows = '';
for (const m of inactiveMembers) {
  tableRows += '<tr style="border-bottom:1px solid #333;">';
  tableRows += '<td style="padding:8px;color:#e8e0d8;">' + m.name + '</td>';
  tableRows += '<td style="padding:8px;color:#888;">' + m.email + '</td>';
  tableRows += '<td style="padding:8px;text-align:right;font-weight:600;color:#ef5350;">' + m.days_inactive + 'j</td>';
  tableRows += '</tr>';
}

const html = [
  '<div style="background-color:#f7f5f2;padding:40px 20px;font-family:Arial,sans-serif;">',
  '<div style="max-width:520px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden;">',
  '<div style="background:#0f0f0f;padding:24px 30px;text-align:center;">',
  '<div style="font-size:20px;font-weight:700;color:#ef5350;">&#x26a0; ALERTE INACTIVIT&Eacute;</div>',
  '<div style="color:#888;font-size:13px;margin-top:4px;">' + inactiveMembers.length + ' membre(s) inactif(s) depuis +14 jours</div>',
  '</div>',
  '<div style="padding:24px;">',
  '<p style="font-size:14px;color:#666;margin-bottom:16px;">Ces membres n\'ont pas &eacute;t&eacute; actifs sur Circle depuis plus de 14 jours. Un message personnel (WhatsApp ou email) est recommand&eacute;.</p>',
  '<div style="background:#0f0f0f;border-radius:8px;padding:16px;overflow-x:auto;">',
  '<table style="width:100%;border-collapse:collapse;font-size:13px;">',
  '<tr style="border-bottom:1px solid #555;"><th style="padding:8px;text-align:left;color:#C27A5A;">Nom</th><th style="padding:8px;text-align:left;color:#C27A5A;">Email</th><th style="padding:8px;text-align:right;color:#C27A5A;">Inactif</th></tr>',
  tableRows,
  '</table>',
  '</div>',
  '</div>',
  '<div style="background:#f7f5f2;padding:16px 30px;text-align:center;font-size:11px;color:#999;">',
  'CS Consulting Strat&eacute;gique &mdash; Alerte automatique ' + today,
  '</div>',
  '</div></div>'
].join('\n');

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.brevo.com/v3/smtp/email',
  headers: brevoHeaders,
  body: {
    sender: { name: 'CS Consulting', email: 'info@facesoulyoga.com' },
    to: [
      { email: 'catherine@csbusiness.fr', name: 'Catherine' },
      { email: 'support@facesoulyoga.com', name: 'Laurie' }
    ],
    subject: 'FSY Alerte: ' + inactiveMembers.length + ' membre(s) inactif(s) depuis +14j',
    htmlContent: html
  }
});

return [{ json: { success: true, inactiveCount: inactiveMembers.length, members: inactiveMembers } }];
